import React, { useState } from "react";
import "./Navbar.css";

function Navbar({ setView, userRole, logout }) {
  const [openMenu, setOpenMenu] = useState(null);

  const toggleMenu = (menu) => {
    setOpenMenu(openMenu === menu ? null : menu);
  };

  return (
    <nav className="navbar">
      <div className="navbar-title">Mi Tiendita</div>

      <ul className="navbar-menu">
        <li onClick={() => setView("dashboard")}>Dashboard</li>

        {userRole === "admin" && (
          <li onClick={() => toggleMenu("inventario")}>
            Inventario ▾
            {openMenu === "inventario" && (
              <ul className="submenu">
                <li onClick={() => setView("gestion")}>Ver productos</li>
                <li onClick={() => setView("gestion")}>Agregar producto</li>
              </ul>
            )}
          </li>
        )}

        <li onClick={() => toggleMenu("config")}>
          Cuenta ▾
          {openMenu === "config" && (
            <ul className="submenu">
              <li onClick={logout} className="logout">Salir</li>
            </ul>
          )}
        </li>
      </ul>
    </nav>
  );
}

export default Navbar;
